#!/usr/bin/env bash
# Regenerate build/appicon.png and build/windows/icon.ico from
# build/appicon.svg (the source of truth — a stylized DB-9 serial
# connector on a rounded navy square). Requires rsvg-convert (from
# librsvg) and ImageMagick 7 (magick).
#
# macOS .icns is generated by Wails from appicon.png at build time, so
# nothing to do there. Linux uses appicon.png directly (embedded at
# runtime and installed under /usr/share/icons/hicolor/). Windows needs
# a multi-resolution .ico because the exe icon is used at every size
# from 16px (taskbar) to 256px (jump-list thumbnail).

set -euo pipefail
cd "$(dirname "$0")"

rsvg-convert -w 1024 -h 1024 appicon.svg -o appicon.png

echo "Wrote $(pwd)/appicon.png"

magick appicon.png -define icon:auto-resize=256,128,64,48,32,16 windows/icon.ico

echo "Wrote $(pwd)/windows/icon.ico"
